import { useGLTF } from "@react-three/drei";

export function Model() {
  const modelPath = "http://localhost:3000/public/uploads/mustang.glb";
  const { scene } = useGLTF(modelPath);

  return (
    <primitive
      object={scene}
      scale={0.03}
      position={[0, -0.5, 0]}
    />
  );
}
